32	   * Creates a model for transcription.
33	   */
34	  transcription(modelId: GroqTranscriptionModelId): TranscriptionModelV3;
35	
36	  /**
37	   * Tools provided by Groq.
38	   */
39	  tools: typeof groqTools;
