48	  /**
49	   * Base URL for the Groq API calls.
50	   */
51	  baseURL?: string;
52	
53	  /**
54	   * API key for authenticating requests.
55	   */
56	  apiKey?: string;
57	
58	  /**
59	   * Custom headers to include in the requests.
60	   */
61	  headers?: Record<string, string>;
62	
63	  /**
