70	/**
71	 * Create an Groq provider instance.
72	 */
73	export function createGroq(options: GroqProviderSettings = {}): GroqProvider {
74	  const baseURL =
75	    withoutTrailingSlash(options.baseURL) ?? 'https://api.groq.com/openai/v1';
76	
77	  const getHeaders = () =>
78	    withUserAgentSuffix(
79	      {
80	        Authorization: `Bearer ${loadApiKey({
81	          apiKey: options.apiKey,
82	          environmentVariableName: 'GROQ_API_KEY',
83	          description: 'Groq',
84	        })}`,
85	        ...options.headers,
86	      },
87	      `ai-sdk/groq/${VERSION}`,
88	    );
89	
90	  const createChatModel = (modelId: GroqChatModelId) =>
91	    new GroqChatLanguageModel(modelId, {
92	      provider: 'groq.chat',
93	      url: ({ path }) => `${baseURL}${path}`,
94	      headers: getHeaders,
95	      fetch: options.fetch,
96	    });
97	
98	  const createLanguageModel = (modelId: GroqChatModelId) => {
99	    if (new.target) {
100	      throw new Error(
101	        'The Groq model function cannot be called with the new keyword.',
102	      );
103	    }
104	
105	    return createChatModel(modelId);
106	  };
107	
108	  const createTranscriptionModel = (modelId: GroqTranscriptionModelId) => {
109	    return new GroqTranscriptionModel(modelId, {
110	      provider: 'groq.transcription',
111	      url: ({ path }) => `${baseURL}${path}`,
112	      headers: getHeaders,
113	      fetch: options.fetch,
114	    });
115	  };
116	
117	  const provider = function (modelId: GroqChatModelId) {
118	    return createLanguageModel(modelId);
119	  };
120	
121	  provider.specificationVersion = 'v3' as const;
122	  provider.languageModel = createLanguageModel;
123	  provider.chat = createChatModel;
124	
125	  provider.embeddingModel = (modelId: string) => {
126	    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
127	  };
128	  provider.textEmbeddingModel = provider.embeddingModel;
129	  provider.imageModel = (modelId: string) => {
130	    throw new NoSuchModelError({ modelId, modelType: 'imageModel' });
131	  };
132	  provider.transcription = createTranscriptionModel;
133	  provider.transcriptionModel = createTranscriptionModel;
134	
135	  provider.tools = groqTools;
136	
137	  return provider;
138	}
139	
140	/**
141	 * Default Groq provider instance.
142	 */
143	export const groq = createGroq();
