1	import { LoadAPIKeyError } from '@ai-sdk/provider';
2	
3	export function loadApiKey({
4	  apiKey,
5	  environmentVariableName,
6	  apiKeyParameterName = 'apiKey',
7	  description,
8	}: {
9	  apiKey: string | undefined;
10	  environmentVariableName: string;
11	  apiKeyParameterName?: string;
12	  description: string;
13	}): string {
14	  if (typeof apiKey === 'string') {
15	    return apiKey;
16	  }
17	
18	  if (apiKey != null) {
19	    throw new LoadAPIKeyError({
20	      message: `${description} API key must be a string.`,
21	    });
22	  }
23	
24	  if (typeof process === 'undefined') {
25	    throw new LoadAPIKeyError({
26	      message: `${description} API key is missing. Pass it using the '${apiKeyParameterName}' parameter. Environment variables is not supported in this environment.`,
27	    });
28	  }
29	
30	  apiKey = process.env[environmentVariableName];
31	
32	  if (apiKey == null) {
33	    throw new LoadAPIKeyError({
34	      message: `${description} API key is missing. Pass it using the '${apiKeyParameterName}' parameter or the ${environmentVariableName} environment variable.`,
35	    });
36	  }
37	
38	  if (typeof apiKey !== 'string') {
39	    throw new LoadAPIKeyError({
40	      message: `${description} API key must be a string. The value of the ${environmentVariableName} environment variable is not a string.`,
41	    });
42	  }
43	
44	  return apiKey;
45	}
