134	export const createBinaryResponseHandler =
135	  (): ResponseHandler<Uint8Array> =>
136	  async ({ response, url, requestBodyValues }) => {
137	    const responseHeaders = extractResponseHeaders(response);
138	
139	    if (!response.body) {
140	      throw new APICallError({
141	        message: 'Response body is empty',
142	        url,
143	        requestBodyValues,
144	        statusCode: response.status,
145	        responseHeaders,
146	        responseBody: undefined,
147	      });
148	    }
149	
150	    try {
151	      const buffer = await response.arrayBuffer();
152	      return {
153	        responseHeaders,
154	        value: new Uint8Array(buffer),
155	      };
156	    } catch (error) {
157	      throw new APICallError({
158	        message: 'Failed to read response as array buffer',
159	        url,
