146	  const provider = function (modelId: AnthropicMessagesModelId) {
147	    if (new.target) {
148	      throw new Error(
149	        'The Anthropic model function cannot be called with the new keyword.',
150	      );
151	    }
152	
153	    return createChatModel(modelId);
154	  };
155	
156	  provider.specificationVersion = 'v3' as const;
157	  provider.languageModel = createChatModel;
158	  provider.chat = createChatModel;
159	  provider.messages = createChatModel;
160	
161	  provider.embeddingModel = (modelId: string) => {
162	    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
163	  };
164	  provider.textEmbeddingModel = provider.embeddingModel;
165	  provider.imageModel = (modelId: string) => {
166	    throw new NoSuchModelError({ modelId, modelType: 'imageModel' });
167	  };
168	
169	  provider.tools = anthropicTools;
170	
171	  return provider;
