154	        }) as JSONSchema7,
155	      ),
156	    {
157	      validate: async value => {
158	        const result = await standardSchema['~standard'].validate(value);
159	        return 'value' in result
160	          ? { success: true, value: result.value }
161	          : {
162	              success: false,
163	              error: new TypeValidationError({
164	                value,
165	                cause: result.issues,
166	              }),
167	            };
168	      },
169	    },
170	  );
171	}
