export function createGroq(options: GroqProviderSettings = {}): GroqProvider {
  const baseURL = withoutTrailingSlash(options.baseURL) ?? 'https://api.groq.com/openai/v1';
  const getHeaders = () => withUserAgentSuffix(
    {
      Authorization: `Bearer ${loadApiKey({
        apiKey: options.apiKey,
        environmentVariableName: 'GROQ_API_KEY',
        description: 'Groq',
      })}`,
      ...options.headers,
    },
    `ai-sdk/groq/${VERSION}`,
  );

  const createChatModel = (modelId: GroqChatModelId) =>
    new GroqChatLanguageModel(modelId, {
      provider: 'groq.chat',
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const provider = function (modelId: GroqChatModelId) {
    return createChatLanguageModel(modelId);
  };

  provider.specificationVersion = 'v3' as const;
  provider.languageModel = createLanguageModel;
  provider.chat = createChatModel;
  provider.transcription = createTranscriptionModel;
  provider.tools = groqTools;

  return provider;
}

