**Image Model Implementation** (`packages/xai/src/xai-image-model.ts`):

```typescript
interface XaiImageModelConfig {
  provider: string;
  baseURL: string | undefined;
  headers: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class XaiImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 3;

  constructor(
    readonly modelId: XaiImageModelId,
    private config: XaiImageModelConfig,
  ) {}

  get provider(): string {
    return this.config.provider;
  }

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<...> {
    const warnings: Array<SharedV3Warning> = [];

    // Feature support validation
    if (size != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'size',
        details: 'Use `aspectRatio` instead.',
      });
    }

    // Parse provider-specific options
    const xaiOptions = await parseProviderOptions({
      provider: 'xai',
      providerOptions,
      schema: xaiImageModelOptions,
    });

    // API call with postJsonToApi
    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${baseURL}${endpoint}`,
      headers: combineHeaders(this.config.headers(), headers),
      body,
      failedResponseHandler: xaiFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(xaiImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images,
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        xai: {...},
      },
    };
  }
}
```

