1	import {
2	  type Experimental_VideoModelV3,
3	  ImageModelV3,
4	  LanguageModelV3,
5	  NoSuchModelError,
6	  ProviderV3,
7	} from '@ai-sdk/provider';
8	import {
9	  FetchFunction,
10	  generateId,
11	  loadApiKey,
12	  withoutTrailingSlash,
13	  withUserAgentSuffix,
14	} from '@ai-sdk/provider-utils';
15	import { XaiChatLanguageModel } from './xai-chat-language-model';
16	import { XaiChatModelId } from './xai-chat-options';
17	import { XaiImageModel } from './xai-image-model';
18	import { XaiImageModelId } from './xai-image-settings';
19	import { XaiResponsesLanguageModel } from './responses/xai-responses-language-model';
20	import { XaiResponsesModelId } from './responses/xai-responses-options';
21	import { xaiTools } from './tool';
22	import { VERSION } from './version';
23	import { XaiVideoModel } from './xai-video-model';
24	import { XaiVideoModelId } from './xai-video-settings';
25	
26	export interface XaiProvider extends ProviderV3 {
27	  /**
28	   * Creates an Xai chat model for text generation.
29	   */
30	  (modelId: XaiChatModelId): LanguageModelV3;
31	
32	  /**
33	   * Creates an Xai language model for text generation.
34	   */
35	  languageModel(modelId: XaiChatModelId): LanguageModelV3;
36	
37	  /**
38	   * Creates an Xai chat model for text generation.
39	   */
40	  chat: (modelId: XaiChatModelId) => LanguageModelV3;
41	
42	  /**
43	   * Creates an Xai responses model for agentic tool calling.
44	   */
45	  responses: (modelId: XaiResponsesModelId) => LanguageModelV3;
46	
47	  /**
48	   * Creates an Xai image model for image generation.
49	   */
50	  image(modelId: XaiImageModelId): ImageModelV3;
51	
52	  /**
53	   * Creates an Xai image model for image generation.
54	   */
55	  imageModel(modelId: XaiImageModelId): ImageModelV3;
56	
57	  /**
58	   * Creates an Xai video model for video generation.
59	   */
60	  video(modelId: XaiVideoModelId): Experimental_VideoModelV3;
61	
62	  /**
63	   * Creates an Xai video model for video generation.
64	   */
65	  videoModel(modelId: XaiVideoModelId): Experimental_VideoModelV3;
66	
67	  /**
68	   * Server-side agentic tools for use with the responses API.
69	   */
70	  tools: typeof xaiTools;
71	
72	  /**
73	   * @deprecated Use `embeddingModel` instead.
74	   */
75	  textEmbeddingModel(modelId: string): never;
76	}
77	
78	export interface XaiProviderSettings {
79	  /**
80	   * Base URL for the xAI API calls.
81	   */
82	  baseURL?: string;
83	
84	  /**
85	   * API key for authenticating requests.
86	   */
87	  apiKey?: string;
88	
89	  /**
90	   * Custom headers to include in the requests.
91	   */
92	  headers?: Record<string, string>;
93	
94	  /**
95	   * Custom fetch implementation. You can use it as a middleware to intercept requests,
96	   * or to provide a custom fetch implementation for e.g. testing.
97	   */
98	  fetch?: FetchFunction;
99	}
100	
101	export function createXai(options: XaiProviderSettings = {}): XaiProvider {
102	  const baseURL = withoutTrailingSlash(
103	    options.baseURL ?? 'https://api.x.ai/v1',
104	  );
105	  const getHeaders = () =>
106	    withUserAgentSuffix(
107	      {
108	        Authorization: `Bearer ${loadApiKey({
109	          apiKey: options.apiKey,
110	          environmentVariableName: 'XAI_API_KEY',
111	          description: 'xAI API key',
112	        })}`,
113	        ...options.headers,
114	      },
115	      `ai-sdk/xai/${VERSION}`,
116	    );
117	
118	  const createChatLanguageModel = (modelId: XaiChatModelId) => {
119	    return new XaiChatLanguageModel(modelId, {
120	      provider: 'xai.chat',
121	      baseURL,
122	      headers: getHeaders,
123	      generateId,
124	      fetch: options.fetch,
125	    });
126	  };
127	
128	  const createResponsesLanguageModel = (modelId: XaiResponsesModelId) => {
129	    return new XaiResponsesLanguageModel(modelId, {
130	      provider: 'xai.responses',
131	      baseURL,
132	      headers: getHeaders,
133	      generateId,
134	      fetch: options.fetch,
135	    });
136	  };
137	
138	  const createImageModel = (modelId: XaiImageModelId) => {
139	    return new XaiImageModel(modelId, {
140	      provider: 'xai.image',
141	      baseURL,
142	      headers: getHeaders,
143	      fetch: options.fetch,
144	    });
145	  };
146	
147	  const createVideoModel = (modelId: XaiVideoModelId) => {
148	    return new XaiVideoModel(modelId, {
149	      provider: 'xai.video',
150	      baseURL,
151	      headers: getHeaders,
152	      fetch: options.fetch,
153	    });
154	  };
155	
156	  const provider = (modelId: XaiChatModelId) =>
157	    createChatLanguageModel(modelId);
158	
159	  provider.specificationVersion = 'v3' as const;
160	  provider.languageModel = createChatLanguageModel;
161	  provider.chat = createChatLanguageModel;
162	  provider.responses = createResponsesLanguageModel;
163	  provider.embeddingModel = (modelId: string) => {
164	    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
165	  };
166	  provider.textEmbeddingModel = provider.embeddingModel;
167	  provider.imageModel = createImageModel;
168	  provider.image = createImageModel;
169	  provider.videoModel = createVideoModel;
170	  provider.video = createVideoModel;
171	  provider.tools = xaiTools;
172	
173	  return provider;
174	}
175	
176	export const xai = createXai();
