86	        }
87	
88	        for (const [key, value] of Object.entries(data)) {
89	          if (
90	            ![
91	              // camelCase known keys
92	              'imageUrl',
93	              'maskUrl',
94	              'guidanceScale',
95	              'numInferenceSteps',
96	              'enableSafetyChecker',
97	              'outputFormat',
98	              'syncMode',
99	              'strength',
100	              'acceleration',
101	              'safetyTolerance',
102	              'useMultipleImages',
103	              // snake_case known keys
104	              'image_url',
105	              'mask_url',
106	              'guidance_scale',
107	              'num_inference_steps',
108	              'enable_safety_checker',
109	              'output_format',
110	              'sync_mode',
111	              'safety_tolerance',
112	            ].includes(key)
113	          ) {
114	            result[key] = value;
115	          }
116	        }
117	
118	        if (deprecatedKeys.length > 0) {
119	          (result as any).__deprecatedKeys = deprecatedKeys;
