1	import { JSONSchema7, TypeValidationError } from '@ai-sdk/provider';
2	import { StandardSchemaV1, StandardJSONSchemaV1 } from '@standard-schema/spec';
3	import * as z3 from 'zod/v3';
4	import * as z4 from 'zod/v4';
5	import { addAdditionalPropertiesToJsonSchema } from './add-additional-properties-to-json-schema';
6	import { zod3ToJsonSchema } from './to-json-schema/zod3-to-json-schema';
7	
8	/**
9	 * Used to mark schemas so we can support both Zod and custom schemas.
10	 */
11	const schemaSymbol = Symbol.for('vercel.ai.schema');
12	
13	export type ValidationResult<OBJECT> =
14	  | { success: true; value: OBJECT }
15	  | { success: false; error: Error };
16	
17	export type Schema<OBJECT = unknown> = {
18	  /**
19	   * Used to mark schemas so we can support both Zod and custom schemas.
20	   */
21	  [schemaSymbol]: true;
22	
23	  /**
24	   * Schema type for inference.
25	   */
26	  _type: OBJECT;
27	
28	  /**
29	   * Optional. Validates that the structure of a value matches this schema,
30	   * and returns a typed version of the value if it does.
31	   */
32	  readonly validate?: (
33	    value: unknown,
34	  ) => ValidationResult<OBJECT> | PromiseLike<ValidationResult<OBJECT>>;
35	
36	  /**
37	   * The JSON Schema for the schema. It is passed to the providers.
38	   */
39	  readonly jsonSchema: JSONSchema7 | PromiseLike<JSONSchema7>;
40	};
41	
42	/**
43	 * Creates a schema with deferred creation.
44	 * This is important to reduce the startup time of the library
45	 * and to avoid initializing unused validators.
46	 *
47	 * @param createValidator A function that creates a schema.
48	 * @returns A function that returns a schema.
49	 */
50	export function lazySchema<SCHEMA>(
51	  createSchema: () => Schema<SCHEMA>,
52	): LazySchema<SCHEMA> {
53	  // cache the validator to avoid initializing it multiple times
54	  let schema: Schema<SCHEMA> | undefined;
55	  return () => {
56	    if (schema == null) {
57	      schema = createSchema();
58	    }
59	    return schema;
60	  };
61	}
62	
63	export type LazySchema<SCHEMA> = () => Schema<SCHEMA>;
64	
65	export type ZodSchema<SCHEMA = any> =
66	  | z3.Schema<SCHEMA, z3.ZodTypeDef, any>
67	  | z4.core.$ZodType<SCHEMA, any>;
68	
69	export type StandardSchema<SCHEMA = any> = StandardSchemaV1<unknown, SCHEMA> &
70	  StandardJSONSchemaV1<unknown, SCHEMA>;
71	
72	export type FlexibleSchema<SCHEMA = any> =
73	  | Schema<SCHEMA>
74	  | LazySchema<SCHEMA>
75	  | ZodSchema<SCHEMA>
76	  | StandardSchema<SCHEMA>;
77	
78	export type InferSchema<SCHEMA> =
79	  SCHEMA extends ZodSchema<infer T>
80	    ? T
81	    : SCHEMA extends StandardSchema<infer T>
82	      ? T
83	      : SCHEMA extends LazySchema<infer T>
84	        ? T
85	        : SCHEMA extends Schema<infer T>
86	          ? T
87	          : never;
88	
89	/**
90	 * Create a schema using a JSON Schema.
91	 *
92	 * @param jsonSchema The JSON Schema for the schema.
93	 * @param options.validate Optional. A validation function for the schema.
94	 */
95	export function jsonSchema<OBJECT = unknown>(
96	  jsonSchema:
97	    | JSONSchema7
98	    | PromiseLike<JSONSchema7>
99	    | (() => JSONSchema7 | PromiseLike<JSONSchema7>),
100	  {
101	    validate,
102	  }: {
103	    validate?: (
104	      value: unknown,
105	    ) => ValidationResult<OBJECT> | PromiseLike<ValidationResult<OBJECT>>;
106	  } = {},
107	): Schema<OBJECT> {
108	  return {
109	    [schemaSymbol]: true,
110	    _type: undefined as OBJECT, // should never be used directly
111	    get jsonSchema() {
112	      if (typeof jsonSchema === 'function') {
113	        jsonSchema = jsonSchema(); // cache the function results
114	      }
115	      return jsonSchema;
116	    },
117	    validate,
118	  };
119	}
120	
121	function isSchema(value: unknown): value is Schema {
122	  return (
123	    typeof value === 'object' &&
124	    value !== null &&
125	    schemaSymbol in value &&
126	    value[schemaSymbol] === true &&
127	    'jsonSchema' in value &&
128	    'validate' in value
129	  );
130	}
131	
132	export function asSchema<OBJECT>(
133	  schema: FlexibleSchema<OBJECT> | undefined,
134	): Schema<OBJECT> {
135	  return schema == null
136	    ? jsonSchema({ properties: {}, additionalProperties: false })
137	    : isSchema(schema)
138	      ? schema
139	      : '~standard' in schema
140	        ? schema['~standard'].vendor === 'zod'
141	          ? zodSchema(schema as ZodSchema<OBJECT>)
142	          : standardSchema(schema as StandardSchema<OBJECT>)
143	        : schema();
144	}
145	
146	function standardSchema<OBJECT>(
147	  standardSchema: StandardSchema<OBJECT>,
148	): Schema<OBJECT> {
149	  return jsonSchema(
150	    () =>
151	      addAdditionalPropertiesToJsonSchema(
152	        standardSchema['~standard'].jsonSchema.input({
153	          target: 'draft-07',
154	        }) as JSONSchema7,
155	      ),
156	    {
157	      validate: async value => {
158	        const result = await standardSchema['~standard'].validate(value);
159	        return 'value' in result
160	          ? { success: true, value: result.value }
161	          : {
162	              success: false,
163	              error: new TypeValidationError({
164	                value,
165	                cause: result.issues,
166	              }),
167	            };
168	      },
169	    },
170	  );
171	}
172	
173	export function zod3Schema<OBJECT>(
174	  zodSchema: z3.Schema<OBJECT, z3.ZodTypeDef, any>,
175	  options?: {
176	    /**
177	     * Enables support for references in the schema.
178	     * This is required for recursive schemas, e.g. with `z.lazy`.
179	     * However, not all language models and providers support such references.
180	     * Defaults to `false`.
181	     */
182	    useReferences?: boolean;
183	  },
184	): Schema<OBJECT> {
185	  // default to no references (to support openapi conversion for google)
186	  const useReferences = options?.useReferences ?? false;
187	
188	  return jsonSchema(
189	    // defer json schema creation to avoid unnecessary computation when only validation is needed
190	    () =>
191	      zod3ToJsonSchema(zodSchema, {
192	        $refStrategy: useReferences ? 'root' : 'none',
193	      }) as JSONSchema7,
194	    {
195	      validate: async value => {
196	        const result = await zodSchema.safeParseAsync(value);
197	        return result.success
198	          ? { success: true, value: result.data }
199	          : { success: false, error: result.error };
200	      },
201	    },
202	  );
203	}
204	
205	export function zod4Schema<OBJECT>(
206	  zodSchema: z4.core.$ZodType<OBJECT, any>,
207	  options?: {
208	    /**
209	     * Enables support for references in the schema.
210	     * This is required for recursive schemas, e.g. with `z.lazy`.
211	     * However, not all language models and providers support such references.
212	     * Defaults to `false`.
213	     */
214	    useReferences?: boolean;
215	  },
216	): Schema<OBJECT> {
217	  // default to no references (to support openapi conversion for google)
218	  const useReferences = options?.useReferences ?? false;
219	
220	  return jsonSchema(
221	    // defer json schema creation to avoid unnecessary computation when only validation is needed
222	    () =>
223	      addAdditionalPropertiesToJsonSchema(
224	        z4.toJSONSchema(zodSchema, {
225	          target: 'draft-7',
226	          io: 'input',
227	          reused: useReferences ? 'ref' : 'inline',
228	        }) as JSONSchema7,
229	      ),
230	    {
231	      validate: async value => {
232	        const result = await z4.safeParseAsync(zodSchema, value);
233	        return result.success
234	          ? { success: true, value: result.data }
235	          : { success: false, error: result.error };
236	      },
237	    },
238	  );
239	}
240	
241	export function isZod4Schema(
242	  zodSchema: z4.core.$ZodType<any, any> | z3.Schema<any, z3.ZodTypeDef, any>,
243	): zodSchema is z4.core.$ZodType<any, any> {
244	  // https://zod.dev/library-authors?id=how-to-support-zod-3-and-zod-4-simultaneously
245	  return '_zod' in zodSchema;
246	}
247	
248	export function zodSchema<OBJECT>(
249	  zodSchema:
250	    | z4.core.$ZodType<OBJECT, any>
251	    | z3.Schema<OBJECT, z3.ZodTypeDef, any>,
252	  options?: {
253	    /**
254	     * Enables support for references in the schema.
255	     * This is required for recursive schemas, e.g. with `z.lazy`.
256	     * However, not all language models and providers support such references.
257	     * Defaults to `false`.
258	     */
259	    useReferences?: boolean;
260	  },
261	): Schema<OBJECT> {
262	  if (isZod4Schema(zodSchema)) {
263	    return zod4Schema(zodSchema, options);
264	  } else {
265	    return zod3Schema(zodSchema, options);
266	  }
267	}
