#### 13. `packages/pixelart/src/pixelart-provider.ts`

**Purpose**: Factory function `createPixelArt` and default `pixelArt` instance.

**Key decisions**:
- Follow the black-forest-labs pattern for an image-only provider: return a plain object implementing `ProviderV3` (not a callable function, since the callable pattern is for chat/language model providers).
- `languageModel()` and `embeddingModel()` throw `NoSuchModelError`.
- `textEmbeddingModel` is an alias for `embeddingModel` (deprecated).
- `image()` and `imageModel()` both create `PixelArtImageModel` instances.
- Auth uses `Bearer` token in `Authorization` header (matching XAI pattern).
- Default base URL: `https://api.pixelart.ai/v1`.
- Environment variable: `PIXELART_API_KEY`.
- User agent suffix: `ai-sdk/pixelart/${VERSION}`.

**Content structure**:
```ts
import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import {
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  baseURL?: string;
  apiKey?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  image(modelId: PixelArtImageModelId): ImageModelV3;
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
  /** @deprecated Use `embeddingModel` instead. */
  textEmbeddingModel(modelId: string): never;
}

export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL = withoutTrailingSlash(
    options.baseURL ?? 'https://api.pixelart.ai/v1',
  );
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt API key',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };

  return {
    specificationVersion: 'v3',
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    imageModel: createImageModel,
    image: createImageModel,
    embeddingModel,
    textEmbeddingModel: embeddingModel,
  };
}

export const pixelArt = createPixelArt();
```

**Design note**: The provider uses the BFL-style return-an-object pattern rather than the XAI-style callable-function pattern. This is because PixelArt has no language model, so calling `pixelArt('model-id')` as a function would have no sensible default behavior. The BFL pattern is the correct choice for image-only providers.

