import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A cute pixel art cat';

function createModel({
  headers,
  currentDate,
}: {
  headers?: () => Record<string, string>;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-standard', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com',
    headers: headers ?? (() => ({ 'api-key': 'test-key' })),
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/images/generations': {
      response: {
        type: 'json-value',
        body: {
          data: [{ b64_json: 'dGVzdA==' }],
        },
      },
    },
  });

  describe('constructor', () => {
    it('should expose correct provider and model information', () => {
      const model = createModel();

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixelart-standard');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });

  describe('doGenerate', () => {
    it('should send correct parameters for generation', async () => {
      const model = createModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(server.calls[0].requestMethod).toBe('POST');
      expect(server.calls[0].requestUrl).toBe(
        'https://api.example.com/images/generations',
      );
      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt,
        n: 1,
      });
    });

    it('should send size parameter when provided', async () => {
      const model = createModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt,
        n: 1,
        size: '512x512',
      });
    });

    it('should return base64 images from b64_json response', async () => {
      const model = createModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBe('dGVzdA==');
    });

    it('should pass headers', async () => {
      const model = createModel({
        headers: () => ({
          'Custom-Provider-Header': 'provider-header-value',
        }),
      });

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: {
          'Custom-Request-Header': 'request-header-value',
        },
      });

      expect(server.calls[0].requestHeaders).toStrictEqual({
        'content-type': 'application/json',
        'custom-provider-header': 'provider-header-value',
        'custom-request-header': 'request-header-value',
      });
    });

    it('should pass style provider option', async () => {
      const model = createModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: {
            style: '8bit',
          },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt,
        n: 1,
        style: '8bit',
      });
    });

    it('should pass pixel_density provider option', async () => {
      const model = createModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: {
            pixel_density: 2,
          },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt,
        n: 1,
        pixel_density: 2,
      });
    });

    it('should pass both style and pixel_density provider options', async () => {
      const model = createModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: {
            style: 'retro',
            pixel_density: 3,
          },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-standard',
        prompt,
        n: 1,
        size: '256x256',
        style: 'retro',
        pixel_density: 3,
      });
    });

    describe('response metadata', () => {
      it('should include timestamp, headers and modelId in response', async () => {
        const testDate = new Date('2024-01-01T00:00:00Z');
        const model = createModel({
          currentDate: () => testDate,
        });

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        });

        expect(result.response).toStrictEqual({
          timestamp: testDate,
          modelId: 'pixelart-standard',
          headers: expect.any(Object),
        });
      });
    });

    describe('warnings', () => {
      it('should warn when aspectRatio is provided', async () => {
        const model = createModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: '16:9',
          seed: undefined,
          providerOptions: {},
        });

        expect(result.warnings).toContainEqual({
          type: 'unsupported',
          feature: 'aspectRatio',
          details:
            'This model does not support the `aspectRatio` option. Use `size` instead.',
        });
      });

      it('should warn when seed is provided', async () => {
        const model = createModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: 42,
          providerOptions: {},
        });

        expect(result.warnings).toContainEqual({
          type: 'unsupported',
          feature: 'seed',
        });
      });

      it('should warn when mask is provided', async () => {
        const model = createModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: {
            type: 'file',
            data: new Uint8Array([255, 255, 255, 0]),
            mediaType: 'image/png',
          },
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        });

        expect(result.warnings).toContainEqual({
          type: 'unsupported',
          feature: 'mask',
        });
      });

      it('should warn when files are provided', async () => {
        const model = createModel();

        const result = await model.doGenerate({
          prompt,
          files: [
            {
              type: 'file',
              data: new Uint8Array([137, 80, 78, 71]),
              mediaType: 'image/png',
            },
          ],
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        });

        expect(result.warnings).toContainEqual({
          type: 'unsupported',
          feature: 'files',
        });
      });

      it('should not warn when size is provided', async () => {
        const model = createModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: '1024x1024',
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        });

        expect(result.warnings).not.toContainEqual(
          expect.objectContaining({ feature: 'size' }),
        );
      });
    });

    it('should handle API errors', async () => {
      server.urls['https://api.example.com/images/generations'].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: {
            message: 'Invalid prompt',
            type: 'invalid_request_error',
          },
        }),
      };

      const model = createModel();
      await expect(
        model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        }),
      ).rejects.toMatchObject({
        message: 'Invalid prompt',
        statusCode: 400,
      });
    });

    it('should respect the abort signal', async () => {
      const model = createModel();
      const controller = new AbortController();

      const generatePromise = model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        abortSignal: controller.signal,
      });

      controller.abort();

      await expect(generatePromise).rejects.toThrow(
        'This operation was aborted',
      );
    });
  });
});

